#include <bits/stdc++.h>
using namespace std;
int n,m,a[202][202],dp[202][202];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    	for(int j=1;j<=m;j++)
    		scanf("%d",&a[i][j]);
    for(int i=1;i<=n;i++)
    	for(int j=1;j<=m;j++)
    		dp[i][j]=max(dp[i-1][j-1],max(dp[i-1][j],dp[i-1][j+1]))+a[i][j];
    printf("%d",max(dp[n][m/2],max(dp[n][m/2+1],dp[n][m/2+2])));
    return 0;
}
